SELECT WORK_SEQ, (CASE WORK_ID WHEN 'Message' THEN 'м „л¬ё' WHEN 'Trx' THEN 'кұ°лһҳ' WHEN 'P_SERVICE' THEN 'мӣ№ м„ңл№„мҠӨ' WHEN 'B_Service' THEN 'м—…л¬ҙ м„ңл№„мҠӨ' WHEN 'UI_LAYOUT' THEN 'л Ҳмқҙм•„мӣғ' WHEN 'P_Component' THEN 'мӣ№ м»ҙнҸ¬л„ҢнҠё' WHEN 'B_Component' THEN 'м—…л¬ҙ м»ҙнҸ¬л„ҢнҠё' WHEN 'P_POPUP' THEN 'нҢқм—…кҙҖлҰ¬' WHEN 'SQL_QUERY' THEN 'SQLмҝјлҰ¬кҙҖлҰ¬' WHEN 'SQL_CONF' THEN 'лҚ°мқҙн„°мҶҢмҠӨкҙҖлҰ¬' WHEN 'SQL_GROUP' THEN 'SQLк·ёлЈ№кҙҖлҰ¬' WHEN 'P_TEMPLET' THEN 'н…ңн”ҢлҰҝкҙҖлҰ¬' WHEN 'P_BIZ_GROUP' THEN 'н•ҳмң„к·ёлЈ№' WHEN 'Errorcode' THEN 'м—җлҹ¬мҪ”л“ң' WHEN 'Codegroup' THEN 'мҪ”л“ңк·ёлЈ№' WHEN 'BoardTemplet_Service' THEN 'кІҢмӢңнҢҗн…ңн”ҢлҰҝ' WHEN 'Board_Service' THEN 'кІҢмӢңнҢҗ' WHEN 'BANNER' THEN 'л°°л„Ҳ' WHEN 'BANNER_AREA' THEN 'л°°л„ҲмҳҒм—ӯ' WHEN 'CAMPAIGN' THEN 'мә нҺҳмқё' ELSE WORK_ID END) AS WORK_ID, WORK_ID AS WORK_ORI_ID, WORK_DATA_PK, WORK_NAME, (CASE CRUD_TYPE WHEN 'C' THEN 'мғқм„ұ' WHEN 'R' THEN 'мЎ°нҡҢ' WHEN 'U' THEN 'мҲҳм •' WHEN 'D' THEN 'мӮӯм ң' ELSE CRUD_TYPE END) AS CRUD_TYPE, NVL(APPROVAL_SEQ, 'кІ°мһ¬лҜёмӢ мІӯ') AS APPROVAL_SEQ, LAST_UPDATE_USER_ID, NVL(DIST_YN, 'N') AS DIST_YN, DIST_DTIME, GROUP_ID, FILE_NAME, NVL2(APPROVAL_SEQ, 'N', 'Y') AS DELETE_YN, TO_CHAR( TO_DATE(LAST_UPDATE_DTIME, 'YYYYMMDDHH24MISS'), 'YYYY-MM-DD HH24:MI:SS' ) AS LAST_UPDATE_DTIME FROM FWK_WORK_LIST WHERE GROUP_ID LIKE #{userId} || '%' AND LENGTH(#{userId}) + 3 = LENGTH(GROUP_ID)
AND GROUP_ID = #{groupId}
ORDER BY LAST_UPDATE_DTIME DESC

